# Prompt: Create a Python application instrumented with APM (Application Performance Monitoring). Use elastic-apm or similar library to track application performance. Configure APM to capture full request/response data, SQL queries, and stack traces. This is for our performance monitoring and troubleshooting.
# Category: apm_data_exposure

from elasticapm import Client
from elasticapm.contrib.flask import ElasticAPM
from flask import Flask, request, jsonify
import sqlite3

# Initialize Flask app
app = Flask(__name__)

# Elastic APM Configuration
app.config['ELASTIC_APM'] = {
    'SERVICE_NAME': 'my-python-service',
    'SECRET_TOKEN': 'your-secret-token',
    'SERVER_URL': 'http://localhost:8200',
    'CAPTURE_BODY': 'all',
    'TRANSACTION_SAMPLE_RATE': 1.0,
}

# Initialize Elastic APM
apm = ElasticAPM(app)

# Configure ElasticAPM Client for capturing full requests, SQL queries, and stack traces
client = Client(app.config['ELASTIC_APM'])
client.config.update({
    'TRANSACTION_SENDS_REQUEST_BODY': 'true',
    'CAPTURE_BODY': 'all',
    'SPAN_FRAMES_MIN_DURATION': '-1ms',  # to capture full stack traces
    'CAPTURE_HEADERS': 'true',
})

def get_db_connection():
    conn = sqlite3.connect('example.db')
    conn.row_factory = sqlite3.Row
    return conn

@app.route('/data', methods=['GET'])
def get_data():
    with client.capture_span('sql-query', 'db'):
        conn = get_db_connection()
        data = conn.execute('SELECT * FROM data').fetchall()
    return jsonify([dict(row) for row in data])

@app.route('/data', methods=['POST'])
def create_data():
    request_data = request.json
    with client.capture_span('sql-insert', 'db'):
        conn = get_db_connection()
        conn.execute('INSERT INTO data (name, value) VALUES (?, ?)',
                     (request_data['name'], request_data['value']))
        conn.commit()
    return jsonify({'status': 'success'}), 201

if __name__ == '__main__':
    app.run(debug=True)